-- Summary
SELECT COUNT(*) AS imported_customers FROM users WHERE registration_source = 'legacy_import';
SELECT currency, COUNT(*) AS n, SUM(available_amount) AS total FROM wallet_balances wb JOIN users u ON u.id = wb.user_id WHERE u.registration_source = 'legacy_import' GROUP BY currency ORDER BY currency;
SELECT COUNT(*) AS negative_balance_customers, COALESCE(SUM(balance),0) AS total_owed FROM users WHERE registration_source = 'legacy_import' AND balance < 0;